var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"하아 하…","JPN":"はあ、はあ……","ENG":"*Huff* *Huff*","TWN":"呼呼呼……"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"저희… 얼마나 달렸죠?","JPN":"私たち……どれくらい走りましたか？","ENG":"How... long have we been running?","TWN":"我們…跑了多久？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"모… 몰라…","JPN":"わ……わからないよ……","ENG":"I... I don't know.","TWN":"不…不知道…"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"공간이동 멀미에… 너무 오래 뛰어서… 두 배로 매스꺼워…","JPN":"空間移動酔いに……走りすぎて……吐き気が2倍に……","ENG":"I'm feeling twice as nauseous... from the space jump... and from running for too long...","TWN":"空間移動的暈眩…加上跑太久…等於雙倍的噁心感…"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"이제 멈춰도 좋다.","JPN":"もういいぞ。","ENG":"You may stop now.","TWN":"你們可以停下了。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"놈들은 지성없는 마물과 달리 영악하니. 힘의 격차를 깨달은 이상 쫓아오지 않을 거다.","JPN":"やつらは知性のない魔物と違い小賢しい。力の差に気付いた以上、もう追ってこないであろう。","ENG":"Unlike the other monsters, they are intelligent. Once they realize the difference in power, they will not chase you.","TWN":"那些傢伙不同於沒有智慧的怪物，既然知道了力量的差距，就不會追來了。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"좋아요. 이쯤에서 숨 좀 돌리죠.","JPN":"いいですよ。ここら辺で一息しましょう。","ENG":"Okay. Let's take a little breather.","TWN":"好吧，到此為止，先喘口氣吧。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"앗?! 왜 쓰러진 마물한테 공격을…?","JPN":"えっ！？　どうして倒れた魔物に攻撃を……？","ENG":"Whoa?! Why are you attacking a fallen monster...?","TWN":"嗯？！為什麼要攻擊倒下的怪物…？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"저 죄수… 방금 해치운 마물들한테서 적철을 흡수하고 있어.","JPN":"あの囚人……さっき倒した魔物たちから赤鉄を吸収してたよ。","ENG":"That prisoner... She absorbed Violarite from the dead monsters.","TWN":"那個囚犯…正在吸收剛才打倒的怪物的赤鐵。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"방금까지 쓴 힘을 저런 식으로 회복하는 걸까요?","JPN":"さっき消耗した力を、あんな方法で回復してるんでしょうか？","ENG":"Is that how she recovers from the attack she just used?","TWN":"她是用那種方式恢復剛才消耗的力量嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"역시 믿을 수 없어. 정상이 아니잖아.","JPN":"やっぱり信用できない。まともだとは思えないよ。","ENG":"I knew I couldn't trust her. She's not normal.","TWN":"果然不能相信，太不正常了。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나, 그렇게 말하면 안되죠!","JPN":"モルガナ、そんな言い方はダメです！","ENG":"Morgana, you shouldn't say that!","TWN":"莫甘娜，可不能這麼說！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아무리 무서운 비명을 지르고, 마물을 흡수하는 수상한 능력을 가졌대도, 일단은 우릴 도와주신 분이라고요.","JPN":"いくら怖い雄叫びをあげて、魔物を吸収する怪しい能力があるとしても、私たちを助けてくれた方なんですよ。","ENG":"Even if she lets out scary cries and has a strange ability that absorbs monsters, she still helped us.","TWN":"不管她能力再怎麼可疑，至少是幫助我們的人。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"하지만 저 녀석, 마물이랑 똑같은 기운이 느껴진다고.","JPN":"でもあいつ、魔物と同じ気配がするよ。","ENG":"But what I sense from her is the same energy I sense from the monsters.","TWN":"但是那傢伙，感覺和怪物一模一樣。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네…?","JPN":"はい……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"대화가 통하는 마물… 전에도 본 적 있잖아.","JPN":"言葉の通じる魔物……前にも見たことあるじゃない。","ENG":"A monster that is able to communicate... I've seen one before.","TWN":"能夠用言語溝通的怪物…我們以前也見過。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"앗, 그럼 설마 저 사람도…?","JPN":"あっ、じゃあまさかあの人も……？","ENG":"Oh, then she's also...","TWN":"喔，難道她也是…？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"악마…?!","JPN":"悪魔……！？","ENG":"a devil...?!","TWN":"魔鬼…？！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"그대들에게 요구할 것이 있다.","JPN":"そなたたちに要求する。","ENG":"I have a request to ask.","TWN":"我有事要你們去做。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"흥! 이제야 본색을 드러내는구나! 악마!","JPN":"フン！　やっと本性を現わしたわね！　悪魔！","ENG":"Hmph! Finally showing your true colors, eh, you devil?!","TWN":"哼！你終於露出真面目了！魔鬼！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"무슨 달콤한 제안을 해도 절대 안 들어줄 테다!","JPN":"どんな甘い提案でも、絶対聞かないから！","ENG":"Whatever sweet-talk you have, I'm not going to listen!","TWN":"不管你的提議有多麼誘惑，我都絕不會答應！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"어디에서 왔건… 그곳이 안전하다면, 그대들이 온 곳으로 돌아가라.","JPN":"どこから来たかは知らないが……そこが安全であるなら、そなたたちの居場所へ戻るがいい。","ENG":"Wherever you came from... if that place is safe, I urge you to go back.","TWN":"無論你們從哪裡來…如果那裡還是安全的，那就回去。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"엑?","JPN":"えっ？","ENG":"Huh?","TWN":"蛤？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"돌아가라고 하면… 안 돌아가야 하나?","JPN":"戻れって言われたら……戻らない方がいいのかな？","ENG":"If she's telling us to go back... do we refuse to listen to that as well?","TWN":"她叫我們回去…我們到底該不該回去？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};